// CODE_Build_Context (n8n Code node)
// ✅ SIN PRICING (pricing se mueve a CODE_Pricing_Compute)
// ✅ Mantiene: hashes, detección cambios, analysis_mode, FIX Flow3 close (solo 1 vez), context_summary_for_ai
// ✅ Incluye: profile/complexity/pricing_key (solo para lookup en Pricing_Base)
// ✅ FIX NUEVO: si viene desde Flow3 (source=flow3_done), forzar análisis completo

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function trimText(text, maxLen) {
  const t = safeStr(text);
  if (!maxLen || maxLen <= 0) return t;
  return t.length > maxLen ? t.slice(0, maxLen) + '…' : t;
}

// Hash simple (determinista) para comparar cambios sin dependencias externas
function simpleHash(str) {
  const s = safeStr(str);
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0; // 32-bit
  }
  return String(h);
}

// ===============================
// 1) Inputs base desde SET_Input
// ===============================
const setInput = $node["SET_Input"]?.json ?? {};
const chat_id = safeStr(setInput.chat_id);

// auto | refresh | analyze
// NOTA: refresh NO fuerza IA; force_refresh sí.
const mode = safeStr(setInput.mode || 'auto').toLowerCase();
const force_refresh = !!setInput.force_refresh;
const source = safeStr(setInput.source || '').toLowerCase();

const extras_limit = Number(setInput.extras_limit ?? 15) || 15;

// Umbrales híbridos extras
const DELTA_CHARS_DEEP = Number(setInput.delta_chars_deep ?? 2000) || 2000;
const DELTA_COUNT_DEEP = Number(setInput.delta_count_deep ?? 3) || 3;

// ===============================
// 2) Lead (Flow 1)
// ===============================
const lead = $node["GS_Lead_Lookup"]?.json ?? {};

// Detectar estado Flow3
const lead_flow_state = safeStr(lead.flow_state).toUpperCase();
const flow3_closed_flag = (lead_flow_state === 'FLOW3_CLOSED');

// ===============================
// 3) Raw transcription (puede no existir)
// ===============================
const rawT = $node["GS_Transcript_Lookup"]?.json ?? {};
const transcription_raw = safeStr(rawT.transcription_raw);
const transcription_clean = safeStr(rawT.transcription_clean);

// Fallback: si no hay transcription, usar voice_concat del Lead
const voice_concat = safeStr(lead.voice_concat);

// Elegimos texto principal
const transcript_main =
  transcription_clean ||
  transcription_raw ||
  voice_concat;

// ===============================
// 4) Extras (0..n filas)
// ===============================
let extrasItems = [];
try {
  extrasItems = $node["GS_Extras_GetMany"]?.all()?.map(x => x.json) ?? [];
} catch (e) {
  extrasItems = [];
}

extrasItems = extrasItems
  .filter(x => safeStr(x.chat_id) === chat_id || chat_id === '')
  .map(x => ({
    extra_id: safeStr(x.extra_id),
    source: safeStr(x.source),
    from: safeStr(x.from),
    received_at: safeStr(x.received_at),
    content_type: safeStr(x.content_type),
    content: safeStr(x.content),
    tags: safeStr(x.tags),
  }));

// Orden desc por received_at (o extra_id)
extrasItems.sort((a, b) => {
  const ad = a.received_at || a.extra_id;
  const bd = b.received_at || b.extra_id;
  return ad < bd ? 1 : ad > bd ? -1 : 0;
});

extrasItems = extrasItems.slice(0, extras_limit);

// ===============================
// 5) Flow2 previo (puede estar vacío)
// ===============================
const flow2prev = $node["GS_Flow2Analysis_Lookup"]?.json ?? {};
const prev_context_hash = safeStr(flow2prev.context_hash);
const has_previous_analysis = !!prev_context_hash;

// hashes previos por componente (si existen)
const prev_hash_lead = safeStr(flow2prev.context_hash_lead);
const prev_hash_transcript = safeStr(flow2prev.context_hash_transcript);
const prev_hash_extras = safeStr(flow2prev.context_hash_extras);

// métricas previas extras (si las guardas)
const prev_extras_count = Number(flow2prev.extras_count ?? 0) || 0;
const prev_extras_text_length = Number(flow2prev.extras_text_length ?? 0) || 0;

// último modo / versión previa (si existe)
const prev_analysis_version = Number(flow2prev.analysis_version ?? 0) || 0;

// ✅ FIX Flow3 cierre NUEVO (solo 1 vez)
const lead_flow3_closed_at = safeStr(lead.flow3_closed_at);
const prev_flow3_closed_at_seen = safeStr(flow2prev.flow3_closed_at_seen);

const is_new_flow3_close =
  flow3_closed_flag &&
  !!lead_flow3_closed_at &&
  (lead_flow3_closed_at !== prev_flow3_closed_at_seen);

// ===============================
// 6) Context Object (sin campos volátiles)
// ===============================
const context_object = {
  meta: {
    chat_id: chat_id || safeStr(lead.chat_id),
    mode,
    force_refresh,
    source,
    extras_limit,
    created_at: safeStr(lead.created_at),
    lang: safeStr(lead.lang || lead.lang_user || 'ES').toUpperCase(),
  },
  lead: {
    // cosmético
    name: safeStr(lead.q1_name || lead.name),
    email: safeStr(lead.q2_email || lead.email),

    // relevante
    company: safeStr(lead.q3_company || lead.company),
    tools: safeStr(lead.q4_tools || lead.tools),
    goal: safeStr(lead.q5_goal || lead.goal),

    // resúmenes Flow1
    client_summary: safeStr(lead.client_summary),
    tech_summary: safeStr(lead.tech_summary),
  },
  transcript: {
    transcription_clean: trimText(transcription_clean, 6000),
    transcription_raw: trimText(transcription_raw, 6000),
    voice_concat: trimText(voice_concat, 6000),
    transcript_main: trimText(transcript_main, 8000),
    audio_count: safeStr(rawT.audio_count || lead.voice_count || lead.audio_count),
    audio_duration_sec: safeStr(rawT.audio_duration_sec),
    voice_last_at: safeStr(lead.voice_last_at || rawT.created_at),
  },
  extras: extrasItems.map(x => ({
    received_at: x.received_at,
    source: x.source,
    content_type: x.content_type,
    content: trimText(x.content, 1200),
    tags: x.tags,
  })),
  flow2_previous: has_previous_analysis ? {
    tier: safeStr(flow2prev.tier),
    score_total: safeStr(flow2prev.score_total),
    confidence: safeStr(flow2prev.confidence),
    quote_range: safeStr(flow2prev.quote_range),
    roadmap: safeStr(flow2prev.roadmap),
    last_updated_at: safeStr(flow2prev.updated_at),
    context_hash: prev_context_hash,
    flow3_closed_at_seen: prev_flow3_closed_at_seen,
  } : null
};

// ===============================
// 7) Texto compacto para IA
// ===============================
const extrasText = context_object.extras.length
  ? context_object.extras.map((e, idx) =>
      `- [${idx + 1}] (${e.received_at || 'sin_fecha'} | ${e.source || 'unknown'} | ${e.content_type || 'text'}) ${e.content}`
    ).join('\n')
  : '(Sin extras adicionales)';

const internalNotesInput = safeStr(setInput.internal_notes);

const context_summary_for_ai = [
  `LEAD`,
  `- chat_id: ${context_object.meta.chat_id}`,
  `- nombre: ${context_object.lead.name}`,
  `- email: ${context_object.lead.email}`,
  `- empresa: ${context_object.lead.company}`,
  `- herramientas: ${context_object.lead.tools}`,
  `- objetivo: ${context_object.lead.goal}`,
  `- idioma: ${context_object.meta.lang}`,
  `- source: ${context_object.meta.source || '(none)'}`,
  ``,
  `FLOW1_SUMMARIES`,
  `- client_summary: ${trimText(context_object.lead.client_summary, 1200)}`,
  `- tech_summary: ${trimText(context_object.lead.tech_summary, 1600)}`,
  ``,
  `TRANSCRIPT_MAIN`,
  trimText(context_object.transcript.transcript_main, 2500),
  ``,
  `EXTRAS`,
  extrasText,
  ``,
  `LANGUAGE_CONTROL`,
  `- user_lang: ${context_object.meta.lang}`,
  `- respond_in: ${context_object.meta.lang}`,
  ``,
  `CONSULTANT_NOTES`,
  internalNotesInput ? `- internal_notes: ${trimText(internalNotesInput, 800)}` : `- internal_notes: (none)`
].join('\n');

// ===============================
// 8) Hashes por componente (sin datos cosméticos)
// ===============================
const leadRelevantPayload = JSON.stringify({
  lang: context_object.meta.lang,
  company: context_object.lead.company,
  tools: context_object.lead.tools,
  goal: context_object.lead.goal,
  client_summary: trimText(context_object.lead.client_summary, 1200),
  tech_summary: trimText(context_object.lead.tech_summary, 1600),
});

const transcriptPayload = JSON.stringify({
  transcript_main: trimText(context_object.transcript.transcript_main, 8000),
});

const extrasPayload = JSON.stringify(context_object.extras);

const context_hash_lead = simpleHash(leadRelevantPayload);
const context_hash_transcript = simpleHash(transcriptPayload);
const context_hash_extras = simpleHash(extrasPayload);

// Hash global
const context_hash = simpleHash(JSON.stringify({
  chat_id: context_object.meta.chat_id,
  lead: context_hash_lead,
  transcript: context_hash_transcript,
  extras: context_hash_extras
}));

// ===============================
// 9) Detectar cambios relevantes
// ===============================
const lead_changed = has_previous_analysis ? (prev_hash_lead ? prev_hash_lead !== context_hash_lead : true) : true;
const transcript_changed = has_previous_analysis ? (prev_hash_transcript ? prev_hash_transcript !== context_hash_transcript : true) : true;
const extras_changed = has_previous_analysis ? (prev_hash_extras ? prev_hash_extras !== context_hash_extras : true) : true;

const relevant_changed =
  !has_previous_analysis ||
  lead_changed ||
  transcript_changed ||
  extras_changed ||
  (prev_context_hash !== context_hash);

// ===============================
// 10) Cambios cosméticos (name/email/lang)
// ===============================
const prev_name = safeStr(flow2prev.name);
const prev_email = safeStr(flow2prev.email);
const prev_lang = safeStr(flow2prev.lang);

const now_name = safeStr(context_object.lead.name);
const now_email = safeStr(context_object.lead.email);
const now_lang = safeStr(context_object.meta.lang);

const cosmetic_changed =
  has_previous_analysis &&
  !relevant_changed &&
  (
    (prev_name && prev_name !== now_name) ||
    (prev_email && prev_email !== now_email) ||
    (prev_lang && prev_lang !== now_lang) ||
    (!prev_name && now_name) ||
    (!prev_email && now_email) ||
    (!prev_lang && now_lang)
  );

// ===============================
// 11) should_analyze_ai (bandera)
// ===============================
const should_analyze_ai =
  force_refresh ||
  (mode === 'analyze') ||
  (source === 'flow3_done') ||
  relevant_changed ||
  is_new_flow3_close;

// ===============================
// 12) Decisión híbrida (SKIP / INCREMENTAL / DEEP)
// ===============================
let analysis_mode = 'SKIP';
const analysis_reasons = [];

// ✅ Si viene del cierre de Flow3, forzar análisis completo
if (source === 'flow3_done') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('source_flow3_done');
}

if (!has_previous_analysis && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('no_previous_analysis');
}

if (force_refresh && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('force_refresh');
}

if (mode === 'analyze' && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('mode_analyze');
}

// ✅ FIX: Solo si el cierre es NUEVO
if (is_new_flow3_close && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('flow3_closed_new');
}

// Cambios estructurales => DEEP
if (lead_changed && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('lead_changed');
}
if (transcript_changed && analysis_mode !== 'DEEP') {
  analysis_mode = 'DEEP';
  analysis_reasons.push('transcript_changed');
}

// Extras => incremental/deep según delta
const extras_count = context_object.extras.length;
const extras_text_length = safeStr(extrasText).length;

const extras_delta_count = extras_count - prev_extras_count;
const extras_delta_chars = extras_text_length - prev_extras_text_length;

const extras_delta_count_norm = Math.max(0, extras_delta_count);
const extras_delta_chars_norm = Math.max(0, extras_delta_chars);

const only_extras_changed = extras_changed && !lead_changed && !transcript_changed;

if (analysis_mode !== 'DEEP') {
  if (only_extras_changed) {
    if (extras_delta_chars_norm > DELTA_CHARS_DEEP || extras_delta_count_norm > DELTA_COUNT_DEEP) {
      analysis_mode = 'DEEP';
      analysis_reasons.push('extras_delta_large');
    } else {
      analysis_mode = 'INCREMENTAL';
      analysis_reasons.push('extras_delta_small');
    }
  } else if (relevant_changed) {
    analysis_mode = 'DEEP';
    analysis_reasons.push('relevant_changed_fallback');
  } else if (cosmetic_changed) {
    analysis_mode = 'INCREMENTAL';
    analysis_reasons.push('cosmetic_changed');
  }
}

if (!should_analyze_ai && analysis_mode !== 'INCREMENTAL' && analysis_mode !== 'DEEP') {
  analysis_mode = 'SKIP';
  if (!analysis_reasons.length) analysis_reasons.push('no_relevant_changes');
}

// Versionado simple (sube en cada análisis real)
const analysis_version = (analysis_mode === 'SKIP') ? prev_analysis_version : (prev_analysis_version + 1);

// ===============================
// 13) Perfil/Complejidad (solo para Pricing_Base lookup)
// ===============================
let profile = safeStr(setInput.profile || lead.profile || '').toUpperCase();
let complexity = safeStr(setInput.complexity || lead.complexity || '').toUpperCase();

if (!profile) profile = 'MICRO';
if (!complexity) complexity = 'LOW';

// Si quieres mantener heurística básica (sin precio):
const toolsText = (context_object.lead.tools || '').toLowerCase();
const goalText = (context_object.lead.goal || '').toLowerCase();
const transcriptText = (context_object.transcript.transcript_main || '').toLowerCase();

if (profile === 'MICRO' && (toolsText.includes('crm') || goalText.includes('crm'))) {
  profile = 'PYME';
}
if (complexity === 'LOW' && (transcriptText.includes('automat') || transcriptText.includes('integrac'))) {
  complexity = 'MEDIUM';
}
if (complexity !== 'HIGH' && (
  transcriptText.includes('centralizada') ||
  transcriptText.includes('multi') ||
  transcriptText.includes('erp') ||
  transcriptText.includes('api')
)) {
  complexity = 'HIGH';
}

const pricing_key = `${profile}|${complexity}`;

// ===============================
// 14) OUTPUT (todo lo que usa Flow2)
// ===============================
return [{
  chat_id: context_object.meta.chat_id,
  lang: context_object.meta.lang,

  context_object,
  context_summary_for_ai,

  // hashes
  context_hash,
  context_hash_lead,
  context_hash_transcript,
  context_hash_extras,

  // deltas extras
  extras_count,
  extras_text_length,
  extras_delta_count: extras_delta_count_norm,
  extras_delta_chars: extras_delta_chars_norm,

  // flags / modes
  has_previous_analysis,
  relevant_changed,
  cosmetic_changed,
  should_analyze_ai,
  analysis_mode,
  analysis_reasons,
  analysis_version,

  // flow3
  flow3_closed_flag,
  is_new_flow3_close,
  flow3_closed_at: lead_flow3_closed_at,
  flow3_closed_at_seen_next: lead_flow3_closed_at || prev_flow3_closed_at_seen,

  // pricing lookup inputs (SIN calcular dinero aquí)
  profile,
  complexity,
  pricing_key,
}];

// CODE_Normalize_Output (n8n Code node)
// Objetivo: Normalizar la salida del nodo AI (Responses API) + merge con base del CODE_Build_Context
// Salida: un item con campos listos para Google Sheets (Update/Append)

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function tryParseJson(text) {
  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

function joinIfArray(v, sep = ' | ') {
  if (Array.isArray(v)) return v.map(x => safeStr(x)).filter(Boolean).join(sep);
  return safeStr(v);
}

// 1) Base desde CODE_Build_Context (para no perder hashes + lead info)
const base = $node["CODE_Build_Context"]?.json ?? {};
const ctx = base.context_object ?? {};
const lead = ctx.lead ?? {};
const meta = ctx.meta ?? {};

const chat_id = safeStr(base.chat_id || meta.chat_id);
const email = safeStr(lead.email || base.email);
const name = safeStr(lead.name || base.name);
const lang = safeStr(meta.lang || base.lang);

// Hashes (estos deben terminar guardados en Flow2_Analysis)
const context_hash = safeStr(base.context_hash);
const context_hash_lead = safeStr(base.context_hash_lead);
const context_hash_transcript = safeStr(base.context_hash_transcript);
const context_hash_extras = safeStr(base.context_hash_extras);

// 2) Respuesta del AI (este node)
const r = $json;

// 2.1) Encontrar el texto JSON dentro del response (Responses API)
let aiText = '';
try {
  const msg = r.output?.find(x => x.type === 'message');
  aiText = msg?.content?.find(c => c.type === 'output_text')?.text || '';
} catch (e) {
  aiText = '';
}

const aiObj = tryParseJson(aiText) || {};

// 3) Normalizar campos AI
const tier = safeStr(aiObj.tier);
const score_total = Number(aiObj.score_total ?? 0) || 0;
const confidence = safeStr(aiObj.confidence);
const top_opportunity = safeStr(aiObj.top_opportunity);

// quick_wins: si viene como array de objetos, lo hacemos string compacto; si viene string, lo usamos
let quick_wins = '';
if (Array.isArray(aiObj.quick_wins)) {
  quick_wins = aiObj.quick_wins.map((x, i) => {
    const t = safeStr(x.title);
    const why = safeStr(x.why);
    const effort = safeStr(x.effort);
    const impact = safeStr(x.impact);
    // formato corto y legible en una celda
    return `${i + 1}) ${t}${effort || impact ? ` (${effort || '-'} / ${impact || '-'})` : ''}${why ? `: ${why}` : ''}`;
  }).join(' || ');
} else {
  quick_wins = safeStr(aiObj.quick_wins);
}

// roadmap / phases
let roadmap = '';
if (Array.isArray(aiObj.phases)) {
  roadmap = aiObj.phases.map(p => {
    const ph = safeStr(p.phase);
    const goal = safeStr(p.goal);
    const del = Array.isArray(p.deliverables) ? p.deliverables.join(', ') : safeStr(p.deliverables);
    return `${ph}: ${goal}${del ? ` -> ${del}` : ''}`;
  }).join(' || ');
} else {
  roadmap = safeStr(aiObj.roadmap);
}

const scope_includes = Array.isArray(aiObj.scope_includes) ? aiObj.scope_includes.join(' | ') : safeStr(aiObj.scope_includes);
const scope_excludes = Array.isArray(aiObj.scope_excludes) ? aiObj.scope_excludes.join(' | ') : safeStr(aiObj.scope_excludes);

// quote_range (objeto -> string)
let quote_range = '';
if (aiObj.quote_range && typeof aiObj.quote_range === 'object') {
  const cur = safeStr(aiObj.quote_range.currency || 'USD');
  const low = safeStr(aiObj.quote_range.low);
  const high = safeStr(aiObj.quote_range.high);
  const model = safeStr(aiObj.quote_range.pricing_model);
  const notes = safeStr(aiObj.quote_range.notes);
  quote_range = `${cur} ${low} - ${high}${model ? ` (${model})` : ''}${notes ? ` | ${notes}` : ''}`;
} else {
  quote_range = safeStr(aiObj.quote_range);
}

const blocking_questions = joinIfArray(aiObj.blocking_questions, ' | ');
const next_step_recommended = safeStr(aiObj.next_step_recommended);

// internal_notes (puede venir del AI o quedar vacío)
const internal_notes = safeStr(aiObj.internal_notes);

// 4) status + timestamps
const flow2_status = 'ANALYZED';
const updated_at = new Date().toISOString();

// 5) Salida final para GS
return [{
  json: {
    // Identidad
    chat_id,
    email,
    name,
    lang,

    // Estado
    flow2_status,
    updated_at,

    // Hashes (claves para optimización)
    context_hash,
    context_hash_lead,
    context_hash_transcript,
    context_hash_extras,

    // Resultado AI
    tier,
    score_total,
    confidence,
    top_opportunity,
    quick_wins,
    roadmap,
    scope_includes,
    scope_excludes,
    quote_range,
    blocking_questions,
    next_step_recommended,
    internal_notes,

    // Debug opcional (si quieres ver qué devolvió el AI tal cual)
    // ai_raw_text: aiText
  }
}];

const chat_id = $node["SET_Input"].json.chat_id;

const now = new Date();
const hours = 24; // <-- cambia aquí
const expires = new Date(now.getTime() + hours * 60 * 60 * 1000);

const iso = now.toISOString().replace(/[-:]/g,'').replace('.','').replace('Z','');
const rnd = Math.random().toString(36).slice(2, 8);

return [{
  chat_id,
  flow_state: "FLOW3_WAITING",
  flow3_request_id: `F3-${chat_id}-${iso}-${rnd}`,
  flow3_opened_at: now.toISOString(),
  flow3_expires_at: expires.toISOString(),
  flow3_questions: (($node["CODE_Normalize_Output"].json.blocking_questions || "") + "").trim(),
  flow3_last_message_at: now.toISOString(),
  flow3_window_hours: hours,
}];

// CODE_Normalize_Report (n8n Code node)
// Objetivo: Normalizar la salida del AI_Report_Builder_DEEP y producir SIEMPRE report_object_json
// para guardarlo en Google Sheets sin romper el flujo.

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function extractAiTextFromNode(nodeName) {
  const n = $node[nodeName];
  if (!n) return '';
  const r = n.json || {};

  // Responses API típico
  try {
    const msg = r.output?.find(x => x.type === 'message');
    const t = msg?.content?.find(c => c.type === 'output_text')?.text;
    if (t) return t;
  } catch (e) {}

  // Variantes comunes
  if (r.output_text) return safeStr(r.output_text);
  if (r.choices?.[0]?.message?.content) return safeStr(r.choices[0].message.content);

  return safeStr(r.text || r.response || r.output || r.content || '');
}

function tryParseJson(text) {
  const t = safeStr(text).trim();
  if (!t) return null;

  // soporta ```json ... ```
  const fenced = t.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  const candidate = fenced ? fenced[1].trim() : t;

  try {
    return JSON.parse(candidate);
  } catch (e) {
    return null;
  }
}

// Identidad
const chat_id =
  safeStr($node["CODE_Build_Context"]?.json?.chat_id) ||
  safeStr($node["CODE_Normalize_Output"]?.json?.chat_id) ||
  safeStr($node["GS_Lead_Lookup"]?.json?.chat_id);

// 1) Tomar texto del report builder
const rawText = extractAiTextFromNode("AI_Report_Builder_DEEP");

// 2) Intentar parsear JSON
const parsed = tryParseJson(rawText);

// 3) Construir SIEMPRE un string para Sheets
let report_object_json = '';
let report_parse_ok = false;

if (parsed) {
  report_object_json = JSON.stringify(parsed);
  report_parse_ok = true;
} else {
  // fallback: guardar texto crudo (recortado por seguridad)
  report_object_json = safeStr(rawText).slice(0, 45000);
  report_parse_ok = false;
}

return [{
  json: {
    chat_id,
    report_object_json,
    report_parse_ok,
    report_raw_len: safeStr(rawText).length
  }
}];

// CODE_Build_HTML_Report (versión segura - inline CSS, sin gradient)
