function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function esc(s) {
  return safeStr(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function tryParseJson(text) {
  try { return JSON.parse(text); } catch (e) { return null; }
}

function asArray(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try {
      const j = JSON.parse(v);
      return Array.isArray(j) ? j : [];
    } catch (e) {
      return [];
    }
  }
  return [];
}

function pill(text) {
  if (!text) return '';
  return '<span style="display:inline-block;font-size:12px;padding:6px 10px;border-radius:999px;background:#f3f4f6;color:#111827;margin-right:6px;">' +
    esc(text) + '</span>';
}

function renderList(items) {
  if (!items || !items.length) return '<div style="color:#6b7280;">—</div>';
  return '<ul style="margin:6px 0 0 18px;padding:0;">' +
    items.map(x => '<li style="margin:4px 0;">' + esc(x) + '</li>').join('') +
    '</ul>';
}

function toNum(v, fallback = null) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function formatInt(n) {
  const num = toNum(n, null);
  if (num === null) return '';
  try {
    return new Intl.NumberFormat('en-US', { maximumFractionDigits: 0 }).format(num);
  } catch (e) {
    return String(Math.round(num));
  }
}

function formatMoneyRange(currency, low, high) {
  const c = safeStr(currency || 'USD').trim() || 'USD';
  const lo = toNum(low, null);
  const hi = toNum(high, null);
  if (lo === null || hi === null) return '';
  return `${c} ${formatInt(lo)} \u2013 ${formatInt(hi)}`; // en dash
}

function asBool(v, fallback = false) {
  if (v === true) return true;
  if (v === false) return false;
  if (v === null || v === undefined || v === '') return fallback;
  const s = String(v).toLowerCase().trim();
  if (['true','1','yes','y','si','sí','on'].includes(s)) return true;
  if (['false','0','no','n','off'].includes(s)) return false;
  return fallback;
}

