// CODE_Pricing_Compute (n8n Code node)
// ✅ Pricing determinista: usa Pricing_Base + Pricing_Adjustments
// ✅ Compatible con columnas: enabled / enable, adjustment_type, multiplier
// ✅ Ajustes pueden venir de SET_Input o Lead (CSV o array)
// ✅ Output: quote_low_final, quote_high_final, pricing_notes

function toNum(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function parseList(v) {
  if (!v) return [];
  if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
  return String(v)
    .split(/[,;\n]/g)
    .map(s => s.trim())
    .filter(Boolean);
}

function roundTo(value, step = 50) {
  const n = toNum(value, 0);
  if (step <= 0) return Math.round(n);
  return Math.round(n / step) * step;
}

// 1) Inputs
const setInput = $node["SET_Input"]?.json ?? {};
const lead = $node["GS_Lead_Lookup"]?.json ?? {};

// 2) Base (rango) desde Pricing_Base
const baseRow = $node["GS_Pricing_Base"]?.json ?? {};
let baseLow = toNum(baseRow.low, 0);
let baseHigh = toNum(baseRow.high, 0);

// Guardrails base
if (baseLow < 0) baseLow = 0;
if (baseHigh < baseLow) baseHigh = baseLow;

// 3) Leer tabla de ajustes
let adjRows = [];
try {
  // Si el nodo devuelve múltiples items (recomendado)
  adjRows = $node["GS_Pricing_Adjustments"].all().map(x => x.json);
} catch (e) {
  // Fallback: si por alguna razón devuelve solo 1
  const one = $node["GS_Pricing_Adjustments"]?.json;
  adjRows = one ? [one] : [];
}

// 4) Map adjustment_type -> multiplier (solo enabled=true)
const multMap = {};
for (const r of adjRows) {
  const key = String(r.adjustment_type ?? r.Adjustment_type ?? "").trim();
  if (!key) continue;

  // soporte para enabled/enable y variaciones
  const enabledRaw =
    r.enabled ??
    r.enable ??
    r.Enabled ??
    r.Enable ??
    r.ENABLED ??
    r.ENABLE ??
    true; // si no existe columna, asumimos habilitado

  const enabled =
    enabledRaw === true ||
    String(enabledRaw).toLowerCase() === "true" ||
    String(enabledRaw) === "1";

  if (!enabled) continue;

  const mRaw = r.multiplier ?? r.Multiplier ?? 1;
  const m = toNum(mRaw, 1);
  multMap[key] = m;
}

// 5) Ajustes solicitados (3 fuentes posibles)
const fromSet = setInput.pricing_adjustments; // recomendado
const fromLead = lead.pricing_adjustments || lead.adjustments || "";
let adjustments = parseList(fromSet || fromLead);

// default
if (!adjustments.length) adjustments = ["normal"];

// 6) Aplicar multiplicadores (en orden)
let finalMult = 1;
const notes = [];

for (const a of adjustments) {
  const k = String(a).trim();
  const m = multMap[k];

  if (m === undefined) {
    notes.push(`Ajuste '${k}' no existe en Pricing_Adjustments → ignorado`);
    continue;
  }

  finalMult *= m;
  notes.push(`Ajuste aplicado: ${k} (x${m})`);
}

// 7) Cálculo final
let quoteLow = baseLow * finalMult;
let quoteHigh = baseHigh * finalMult;

// Guardrails extra (configurables desde SET_Input)
const floor = toNum(setInput.pricing_floor ?? 300, 300);     // mínimo absoluto
const ceil = toNum(setInput.pricing_ceil ?? 50000, 50000);   // techo

quoteLow = Math.max(quoteLow, floor);
quoteHigh = Math.max(quoteHigh, quoteLow);

quoteLow = Math.min(quoteLow, ceil);
quoteHigh = Math.min(quoteHigh, ceil);

// Redondeo “bonito”
const roundStep = toNum(setInput.pricing_round_step ?? 50, 50);
quoteLow = roundTo(quoteLow, roundStep);
quoteHigh = roundTo(quoteHigh, roundStep);

// 8) Output
return [{
  base_low: baseLow,
  base_high: baseHigh,
  final_multiplier: finalMult,
  adjustments_applied: adjustments,
  quote_low_final: quoteLow,
  quote_high_final: quoteHigh,
  pricing_notes: notes.join(" | "),
}];
